INSERT INTO supply_claim_export_file(
    id, claim_id, file_name, storage_key, status, summary_text, download_token, expire_at, created_by, created_time
) VALUES (
    #{id}, #{claimId}, #{fileName}, #{storageKey}, #{status}, #{summaryText}, #{downloadToken}, #{expireAt}, #{createdBy}, #{createdTime}
)

mapper.select:
SELECT *
FROM supply_claim_export_file
WHERE claim_id = #{claimId}
ORDER BY created_time DESC
LIMIT #{limit}
